#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    unordered_set<int> nums;
    for(int i = 0; i < n; i++) {
        int x; cin >> x;
        nums.insert(x);
    }
    int longest_streak = 0;
    for (int num : nums) {
        if (nums.find(num - 1) == nums.end()) {
            int current_num = num;
            int current_streak = 1;
            while (nums.find(current_num + 1) != nums.end()) {
                current_num += 1;
                current_streak += 1;
            }
            longest_streak = max(longest_streak, current_streak);
        }
    }
    cout << longest_streak << endl;
    return 0;
}
